3_real_world_example.code:
const username = 'Global_Admin'; // Global Scope

function processUser() {
  // Function Scope (Shadows the global variable)
  const username = 'Local_User'; 

  if (true) {
    // Block Scope (let/const are trapped in here)
    const username = 'Block_User';
    console.log(username); // 'Block_User'
  }

  console.log(username); // 'Local_User'
}

processUser();
console.log(username); // 'Global_Admin'

